def letter_grade(score):
    """Return the letter grade for a numeric score.

    A: 90-100, B: 80-89, C: 70-79, D: 60-69, F: below 60
    """
    if score > 90:
        return 'A'
    elif score >= 80:
        return 'B'
    elif score >= 70:
        return 'C'
